(function(){"use strict";var data=window.hivepressActionBarFrontendData||{},bar=document.querySelector(".hp-action-bar");if(!bar){return}if(data.safeArea){var meta=document.querySelector('meta[name="viewport"]');if(meta){var content=meta.getAttribute("content")||"";if(content.indexOf("viewport-fit")===-1){meta.setAttribute("content",content?content+",viewport-fit=cover":"viewport-fit=cover")}}else if(document.head){meta=document.createElement("meta");meta.setAttribute("name","viewport");meta.setAttribute("content","width=device-width, initial-scale=1, viewport-fit=cover");document.head.appendChild(meta)}}function syncPadding(){if(!document.body){return}if(window.getComputedStyle(bar).display==="none"){document.body.style.paddingBottom=""}else{document.body.style.paddingBottom=bar.offsetHeight+"px"}}syncPadding();window.addEventListener("resize",syncPadding);window.addEventListener("orientationchange",syncPadding);if(window.ResizeObserver){new window.ResizeObserver(syncPadding).observe(bar)}var path=window.location.pathname.replace(/\/+$/,"")||"/",matched=false;Array.prototype.forEach.call(bar.querySelectorAll(".hp-action-bar__item"),function(item){if(matched){return}var href=item.getAttribute("href");if(!href||href.charAt(0)==="#"){return}var link=document.createElement("a");link.href=href;if(link.host!==window.location.host){return}var linkPath=link.pathname.replace(/\/+$/,"")||"/";if(linkPath!==path){return}if(link.search&&link.search!==window.location.search){return}item.classList.add("hp-action-bar__item--active");item.setAttribute("aria-current","page");matched=true})})();
